// Lấy dữ liệu đầu vào
const items = $input.all();

// Tạo object để nhóm theo Mã SR
const grouped = {};

// Duyệt qua từng item
items.forEach(item => {
  const maSR = item.json['Mã SR'];
  const email = item.json['Email'];

  // Nếu chưa có Mã SR này trong grouped
  if (!grouped[maSR]) {
    grouped[maSR] = {
      'Mã SR': maSR,
      'Email_List': []
    };
  }

  // Thêm email vào list
  grouped[maSR]['Email_List'].push(email);
});

// Chuyển đổi thành array và nối Email bằng dấu phẩy
const result = Object.values(grouped).map(group => ({
  'Mã SR': group['Mã SR'],
  'Email': group['Email_List'].join(',')
}));

return result.map(item => ({json: item}));

// Lấy tất cả items từ input
const items = $input.all();

// Nhóm items theo SKU
const itemsBySKU = {};
items.forEach(item => {
  const sku = item.json.SKU;
  if (!itemsBySKU[sku]) {
    itemsBySKU[sku] = [];
  }
  itemsBySKU[sku].push(item.json);
});

// Kiểm tra từng SKU
const results = [];
let issueNumber = 1;

// Ngày hiện tại
const today = new Date();

Object.keys(itemsBySKU).forEach(sku => {
  const skuItems = itemsBySKU[sku];

  // Lọc items ở zone "Trưng bày hàng bán mới"
  const displayZoneItems = skuItems.filter(item => 
    item.BIN_zone === "Trưng bày hàng bán mới"
  );

  // Lọc items ở zone "Lưu kho hàng bán mới"
  const storageZoneItems = skuItems.filter(item => 
    item.BIN_zone === "Lưu kho hàng bán mới"
  );

  // Chỉ xử lý nếu SKU có sản phẩm ở CẢ 2 zone
  if (displayZoneItems.length === 0 || storageZoneItems.length === 0) {
    return;
  }

  // Sắp xếp serial trưng bày theo ngày (cũ nhất lên đầu)
  const sortedDisplayItems = displayZoneItems.sort((a, b) => {
    return new Date(a.Date_import_company) - new Date(b.Date_import_company);
  });

  // Sắp xếp serial lưu kho theo ngày (mới nhất lên đầu)
  const sortedStorageItems = storageZoneItems.sort((a, b) => {
    return new Date(b.Date_import_company) - new Date(a.Date_import_company);
  });

  // Lọc serial trưng bày cũ hơn serial lưu kho mới nhất
  const newestStorageDate = new Date(sortedStorageItems[0].Date_import_company);
  const olderDisplayItems = sortedDisplayItems.filter(item => {
    return new Date(item.Date_import_company) < newestStorageDate;
  });

  // Ghép cặp: Serial trưng bày cũ nhất với serial lưu kho mới nhất
  const pairCount = Math.min(olderDisplayItems.length, sortedStorageItems.length);

  for (let i = 0; i < pairCount; i++) {
    const displayItem = olderDisplayItems[i];
    const storageItem = sortedStorageItems[i];

    // Tính số ngày chênh lệch giữa 2 serial
    const displayDate = new Date(displayItem.Date_import_company);
    const storageDate = new Date(storageItem.Date_import_company);
    const diffMs = storageDate - displayDate;
    const diffDays = Math.floor(diffMs / (1000 * 60 * 60 * 24));

    // Tính số ngày tồn kho tính đến hiện tại
    const displayAgeMs = today - displayDate;
    const displayAgeDays = Math.floor(displayAgeMs / (1000 * 60 * 60 * 24));

    const storageAgeMs = today - storageDate;
    const storageAgeDays = Math.floor(storageAgeMs / (1000 * 60 * 60 * 24));

    results.push({
      'No.': issueNumber++,
      SKU: sku,
      Name: displayItem.SKU_name,
      SerialDisplay: displayItem.Serial,
      DisplayImportDate: displayItem.Date_import_company,
      DisplayAgeDays: displayAgeDays,
      SerialDisplayBin: displayItem.Location || 'N/A',
      StorageSerial: storageItem.Serial,
      StorageImportDate: storageItem.Date_import_company,
      StorageAgeDays: storageAgeDays,
      StorageSerialBin: storageItem.Location || 'N/A',
      DiffDays: diffDays,
      TotalInDisplay: displayZoneItems.length,
      TotalInStorage: storageZoneItems.length,
      TotalOlderDisplay: olderDisplayItems.length,
      TotalItems: skuItems.length,
      CategoryId: displayItem.Category_ID || 'N/A',
      CategoryName: displayItem.Category_name || 'N/A',
      Message: `Serial trưng bày ${displayItem.Serial} (tồn ${displayAgeDays} ngày) cần thay thế bằng serial lưu kho ${storageItem.Serial} (tồn ${storageAgeDays} ngày)`
    });
  }
});

// Trả về array of items
return results;

